// import { mapState } from "vuex";
import Modal from "../../plugins/modals";
import { ipcRenderer } from "electron";
import { mapState } from "vuex";
export default {
  data() {
    return {
      visible: false,
      canAct: true,
      timeout: null
    };
  },
  computed: mapState({
    matchFoundState: state => state.matchFoundState
  }),
  methods: {
    getMMTitle() {
      if (!this.canAct) {
        return this.$translate.text("MMDL_TITLE_WAIT");
      } else {
        return this.$translate.text("MMDL_TITLE_MATCH_FOUND");
      }
    },
    hide() {
      this.visible = false;
      this.$store.dispatch("clearMatchFoundState");
    },
    show() {
      this.visible = true;
    },
    acceptMatch() {
      if (!this.canAct) return;
      this.canAct = false;
      this.$socket.sendLobbyMessage("LOBBY_CHAMPSELECT_ACCEPT", {}, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        console.log(response);
      });
    },
    denyMatch() {
      if (!this.canAct) return;
      this.canAct = false;
      Modal.EventBus.$emit("matchmaking-reset-timer");
      this.$socket.sendLobbyMessage("LOBBY_CHAMPSELECT_DENY", {}, (response, error) => {
        if (error) {
          console.log("Flyback error:");
          console.log(error);
        }
        console.log(response);
      });
    }
  },
  beforeMount() {
    Modal.EventBus.$on("matchmaking-show", () => {
      this.show();
      ipcRenderer.send("focusApp");
      this.$sound.template("CORE_MATCH_FOUND");
      this.timeout = setTimeout(() => {
        this.hide();
        this.canAct = true;
      }, 15000);
    });
    Modal.EventBus.$on("matchmaking-hide", () => {
      this.hide();
      this.canAct = true;
    });
  },
  updated() {
    if (this.$refs.modal) {
      this.$refs.modal.focus();
    }
  }
};
